import{_ as t,a as o,b as i,c as a,d as s}from"./chunks/sidebar-usage-limit.BZbSXi96.js";import{_ as r}from"./chunks/common-target-settings.CA2Xo8wE.js";import{_ as n}from"./chunks/sidebar-schedule-dates.DTnHEJAO.js";import{_ as l,a as c}from"./chunks/common-product-discount-message-format.BUy9b524.js";import{_ as p,c as u,o as d,ag as h}from"./chunks/framework.B58IbkZx.js";const g="/1.0.0-PRO/assets/selection-early-bird.DgZV8dTw.png",m="/1.0.0-PRO/assets/early-bird-tier-single.x6nu3s_w.png",f="/1.0.0-PRO/assets/early-bird-tiers-multiple.C9F8YuN2.png",D=JSON.parse('{"title":"Campaign Type: Early Bird Discount","description":"","frontmatter":{},"headers":[],"relativePath":"campaigns/early-bird-discounts.md","filePath":"campaigns/early-bird-discounts.md","lastUpdated":1769871666000}'),y={name:"campaigns/early-bird-discounts.md"};function b(S,e,T,_,v,w){return d(),u("div",null,e[0]||(e[0]=[h('<h1 id="campaign-type-early-bird-discount" tabindex="-1">Campaign Type: Early Bird Discount <a class="header-anchor" href="#campaign-type-early-bird-discount" aria-label="Permalink to &quot;Campaign Type: Early Bird Discount&quot;">​</a></h1><p>An <strong>Early Bird Discount</strong> is a powerful marketing tool designed to create urgency and drive rapid sales by rewarding your first customers. The discount is based on the total number of <strong>successful orders</strong> that have already used the campaign.</p><p>This is the perfect campaign type for scenarios like:</p><ul><li>&quot;50% off for the first 100 customers!&quot;</li><li>&quot;Launch Special: The first 50 orders get $20 off, the next 100 get $10 off.&quot;</li><li>Creating a flash sale with a limited number of available slots.</li></ul><div class="warning custom-block"><p class="custom-block-title">Important: Order vs. Quantity</p><p>An Early Bird discount is based on the number of <strong>orders</strong>, not the quantity of items purchased. If one customer buys 100 items in a single transaction, it only counts as <strong>one</strong> use toward the campaign&#39;s limit.</p></div><p>This guide will walk you through every field required to set up this campaign type.</p><h2 id="step-1-select-your-campaign-type" tabindex="-1">Step 1: Select Your Campaign Type <a class="header-anchor" href="#step-1-select-your-campaign-type" aria-label="Permalink to &quot;Step 1: Select Your Campaign Type&quot;">​</a></h2><p>To begin, navigate to <strong>CampaignBay → Add Campaign</strong>.</p><p><img src="'+g+'" alt="Select Campaign Type"></p><ul><li><strong>Select Discount Type:</strong> Choose <strong><code>EarlyBird Discount</code></strong> from the list. This will reveal the tiered configuration for rewarding your first customers.</li></ul><p><img src="'+t+'" alt="Campaign Title"></p><ul><li><strong>Campaign Title:</strong> Give your campaign a clear and descriptive name (e.g., &quot;New Product Launch Offer&quot;).</li></ul><p><img src="'+o+'" alt="Save Actions"></p><ul><li><strong>Select Status:</strong><ul><li><strong>Active:</strong> The campaign will be live immediately (or on its scheduled start time).</li><li><strong>Inactive:</strong> Save the campaign as a draft.</li></ul></li></ul><h2 id="step-2-set-the-discount-target" tabindex="-1">Step 2: Set the Discount Target <a class="header-anchor" href="#step-2-set-the-discount-target" aria-label="Permalink to &quot;Step 2: Set the Discount Target&quot;">​</a></h2><p>This crucial step defines which products in your store are eligible for the early bird discount.</p><p><img src="'+r+'" alt="Discount Target"></p><p>The <strong>DISCOUNT TARGET</strong> dropdown provides powerful options to control the scope of your campaign, such as applying it to the entire store, specific products, or categories.</p><div class="info custom-block"><p class="custom-block-title">Learn More About Targeting</p><p>The &quot;Discount Target&quot; setting is a powerful feature shared by all campaign types. We&#39;ve created a dedicated guide to explain all of its options and conditional fields in detail.</p><p><strong><a href="./../core-concepts/targeting.html">Read the Full Guide: Targeting →</a></strong></p></div><h2 id="step-3-define-discount-tiers-for-first-sales" tabindex="-1">Step 3: Define Discount Tiers For First Sales <a class="header-anchor" href="#step-3-define-discount-tiers-for-first-sales" aria-label="Permalink to &quot;Step 3: Define Discount Tiers For First Sales&quot;">​</a></h2><p>This is the core of the Early Bird Discount. Here you will define the tiers based on the number of successful orders.</p><p><img src="'+m+'" alt="Define Early Bird Tiers"></p><ul><li><strong>For First:</strong> Enter the number of orders for this tier. For example, entering <code>10</code> here means this tier applies to the first 10 successful orders.</li><li><strong>Orders (e.g., 1 - 10):</strong> This label automatically updates to show the range of orders covered by this tier.</li><li><strong>Get:</strong> The numeric value of the discount.</li><li><strong>% / Fixed ($) (Mode):</strong> The type of discount to apply (Percentage or Fixed Currency amount).</li></ul><p><img src="'+f+'" alt="Multiple Tiers"></p><ul><li><strong>+ Add another tier:</strong> Click this to add multiple levels of Early Bird offers (e.g., &quot;For Next 10 Orders...&quot;). Each subsequent tier will automatically pick up where the previous one left off.</li></ul><h3 id="how-tiers-work" tabindex="-1">How Tiers Work <a class="header-anchor" href="#how-tiers-work" aria-label="Permalink to &quot;How Tiers Work&quot;">​</a></h3><p>The tiers work sequentially from top to bottom.</p><p><strong>Example Tier Setup:</strong></p><ul><li><strong>Tier 1:</strong> For First <code>Sales (1 - 100)</code>, give <code>50</code> <code>%</code></li><li><strong>Tier 2:</strong> For First <code>Sales (1 - 250)</code>, give <code>25</code> <code>%</code></li></ul><p><strong>In this scenario:</strong></p><ul><li>Orders 1 through 100 will receive a 50% discount.</li><li>Orders 101 through 250 will receive a 25% discount.</li><li>Order 251 and beyond will receive no discount from this campaign.</li></ul><h2 id="step-4-set-conditions-optional" tabindex="-1">Step 4: Set Conditions (Optional) <a class="header-anchor" href="#step-4-set-conditions-optional" aria-label="Permalink to &quot;Step 4: Set Conditions (Optional)&quot;">​</a></h2><p>You can add specific rules to restrict who can use this discount (e.g., specific User Roles).</p><p><img src="'+i+'" alt="Conditions Overview"></p><p><strong><a href="./../core-concepts/conditions.html">Read the Full Guide: How to Use Conditions →</a></strong></p><h2 id="step-5-set-other-configurations-optional" tabindex="-1">Step 5: Set Other Configurations (Optional) <a class="header-anchor" href="#step-5-set-other-configurations-optional" aria-label="Permalink to &quot;Step 5: Set Other Configurations (Optional)&quot;">​</a></h2><p>This section provides additional rules for your campaign.</p><p><img src="'+a+'" alt="Exclude Sale Item"></p><ul><li><strong>Exclude Sale Items:</strong> Check this box if you do not want this campaign&#39;s discount to apply to products that are already on sale in WooCommerce. This is useful for preventing &quot;double discounting.&quot;</li></ul><p><img src="'+s+'" alt="Enable Usage Limit"></p><ul><li><strong>Enable Usage Limit:</strong> Check this box to set a maximum number of times this campaign can be used across your entire store. Once the limit is reached, the campaign will automatically become inactive.</li></ul><h2 id="step-6-set-the-schedule-optional" tabindex="-1">Step 6: Set the Schedule (Optional) <a class="header-anchor" href="#step-6-set-the-schedule-optional" aria-label="Permalink to &quot;Step 6: Set the Schedule (Optional)&quot;">​</a></h2><p>For a Scheduled Discount, setting the duration is essential. This section controls when your campaign will automatically start and end.</p><p><img src="'+n+'" alt="Enable Schedule"></p><ul><li><strong>Start Time / End Time:</strong> Use the date and time pickers to set the exact moment for the campaign to activate and expire.</li></ul><div class="tip custom-block"><p class="custom-block-title">Timezone Information</p><p>All dates and times are based on the timezone you have configured in your main WordPress settings under <strong>Settings → General → Timezone</strong>. The system automatically handles all UTC conversions for you.</p></div><div class="info custom-block"><p class="custom-block-title">Learn More About Automation</p><p>The status of your campaign is closely tied to the scheduling system, which uses WordPress Cron to automate activation and expiration.</p><p><strong><a href="./../core-concepts/scheduling-and-automation.html">Read the Full Guide: Scheduling &amp; Automation →</a></strong></p></div><h2 id="step-7-display-configurations" tabindex="-1">Step 7: Display Configurations <a class="header-anchor" href="#step-7-display-configurations" aria-label="Permalink to &quot;Step 7: Display Configurations&quot;">​</a></h2><p>This section controls how the offer is communicated to the customer, both on the product page and in their cart.</p><p><img src="'+l+'" alt="Show Promotional Message"></p><ul><li><strong>Show Product Page Promotional Message:</strong> Toggle this to enable or disable the custom message on the product pages.</li></ul><p><img src="'+c+'" alt="Product Page Promotional Message Format"></p><ul><li><p><strong>Product Page Discount Message Format:</strong> Customize the promotional text using placeholders like <code>{percentage_off}</code> or <code>{amount_off}</code>.</p><ul><li><em>Example:</em> <code>Early Bird Special! Get {percentage_off}% off for a limited time!</code></li></ul></li><li><p><strong>Cart Page Discount Message Format:</strong> Enter a message to display on the cart page when the discount is applied.</p><ul><li><em>Example:</em> <code>Early Bird discount applied: {discount_amount}</code></li></ul></li><li><p><strong>Cart Page Message Location:</strong> Choose where the cart message should appear (e.g., next to the line item name).</p></li></ul><h2 id="step-8-save-the-campaign" tabindex="-1">Step 8: Save the Campaign <a class="header-anchor" href="#step-8-save-the-campaign" aria-label="Permalink to &quot;Step 8: Save the Campaign&quot;">​</a></h2><p>Once you have configured all the options, click the <strong>Save Campaign</strong> button at the top right of the page. After saving, you will be redirected back to the &quot;All Campaigns&quot; list.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>Next, learn how to create campaigns that offer &quot;Buy One, Get One&quot; style deals.</p><ul><li><strong><a href="./bogo-discounts.html">Creating a BOGO Discount →</a></strong></li></ul>',58)]))}const O=p(y,[["render",b]]);export{D as __pageData,O as default};
